update guide_schedule
guide_id = #{guideId}, group_id = #{groupId}, assign_time = #{assignTime}, start_time = #{startTime}, end_time = #{endTime}, load_count = #{loadCount}, status = #{status}, create_by = #{createBy}, create_time = #{createTime}, update_by = #{updateBy}, update_time = #{updateTime}, remark = #{remark}, del_flag = #{delFlag},
where schedule_id = #{scheduleId}

UPDATE guide_schedule gs
    INNER JOIN tourist_group tg ON gs.group_id = tg.group_id
    SET gs.status = '3',
        gs.end_time = #{endTime}
WHERE gs.guide_id = #{guideId}
  AND tg.group_code = #{groupCode}
  AND gs.del_flag = '0'
  AND gs.status = '1'
  AND DATE(gs.start_time) = CURDATE()
